from django.shortcuts import render, redirect
from django.contrib.auth import login as auth_login
from django.contrib.auth.models import User
from django.http import HttpResponse
import xml.etree.ElementTree as ET
from onelogin.saml2.auth import OneLogin_Saml2_Auth
from django.views.decorators.csrf import csrf_exempt

def prepare_saml_auth(request):
    # Prepare SAML authentication
    auth = OneLogin_Saml2_Auth(request, custom_base_path='/path/to/saml/')
    return auth

@csrf_exempt
def acs(request):
    auth = prepare_saml_auth(request)
    auth.process_response()
    errors = auth.get_errors()
    
    if len(errors) > 0:
        return HttpResponse('Error: ' + ', '.join(errors), status=400)
    
    user_data = auth.get_attributes()
    name_id = auth.get_nameid()

    if user_data and name_id:
        # Assume the first attribute is the username
        username = user_data['username'][0]
        email = user_data['email'][0]

        user, created = User.objects.get_or_create(username=username, defaults={'email': email})
        if created:
            user.set_unusable_password()  # Or set a random password
            user.save()

        auth_login(request, user)
        
        return redirect('/')
    
    return HttpResponse('No user data found.', status=400)

def validate_saml_xml(saml_xml):
    try:
        root = ET.fromstring(saml_xml)
        return root.tag == '{urn:oasis:names:tc:SAML:2.0:assertion}Assertion'
    except ET.ParseError:
        return False

