def saml_redirect(request):
    auth = prepare_saml_auth(request)
    return redirect(auth.login())  # Redirect to IdP login page

def logout(request):
    auth = prepare_saml_auth(request)
    return HttpResponse(auth.logout())  # Redirect to IdP logout page

